#!/usr/bin/env bash
# 项目共享系统 — 会话启动快照生成器
# 供 Agent 在会话启动时调用，快速了解当前项目状态

WORKSPACE="${CLAWHUB_WORKDIR:-$HOME/.openclaw/workspace}"
JSON_PATH="$WORKSPACE/projects_status.json"
OUTPUT_FILE="${1:-$WORKSPACE/projects_snapshot.md}"

if [ ! -f "$JSON_PATH" ]; then
    echo "错误: 未找到 $JSON_PATH"
    exit 1
fi

# 生成快照
cat > "$OUTPUT_FILE" << 'HEADER'
# 📋 项目状态快照
<!-- Auto-generated by project-sharing-system -->
HEADER

echo "" >> "$OUTPUT_FILE"
echo "**生成时间**: $(date '+%Y-%m-%d %H:%M:%S')" >> "$OUTPUT_FILE"
echo "" >> "$OUTPUT_FILE"

# 使用 Python 解析 JSON 并生成结构化输出
python3 -c "
import json
import sys

with open('$JSON_PATH') as f:
    data = json.load(f)

projects = data.get('projects', [])
active = [p for p in projects if p.get('status') == 'in_progress']
completed = [p for p in projects if p.get('status') == 'completed']
total = len(projects)

output = []

# 活跃项目摘要
output.append(f'**活跃项目**: {len(active)} 个')
for p in active:
    output.append(f'- 🔄 [{p[\"name\"]}]({p.get(\"id\",\"\")}): {p.get(\"current_task\",\"\")}')
    
output.append('')
output.append(f'**已完成项目**: {len(completed)} 个')
for p in completed:
    output.append(f'- ✅ {p[\"name\"]}')
    
output.append('')
output.append(f'**总计**: {total} 个项目 | 最后更新: {data.get(\"last_updated\",\"\")}')
output.append(f'**更新者**: {data.get(\"updated_by\",\"\")}')

print('\n'.join(output))
" >> "$OUTPUT_FILE"

echo "snapshot_path: $OUTPUT_FILE"
echo "active_projects: $(python3 -c "import json,d;d=json.load(open('$JSON_PATH'));print(sum(1 for p in d['projects'] if p['status']=='in_progress'))")"
echo "total_projects: $(python3 -c "import json;d=json.load(open('$JSON_PATH'));print(len(d['projects']))")"
